using CSharpier.Core.CSharp;
using Google.Protobuf.Reflection;
using LightProto.ProtoGen;
using ProtoBuf.Reflection;

namespace LightProto.ProtoGen.Tests;

/// <summary>
/// Tests for <see cref="LightProtoCSharpGenerator"/>.
///
/// Each code-generation test asserts that the full generated file, once formatted by CSharpier,
/// is identical to the expected file string, also formatted by CSharpier.
/// Because CSharpier produces deterministic output for semantically identical code, trivial
/// whitespace differences in the expected string are automatically normalised.
/// </summary>
public class LightProtoCSharpGeneratorTests
{
    // -------------------------------------------------------------------------
    // Helpers
    // -------------------------------------------------------------------------

    /// <summary>
    /// Parses <paramref name="protoSchema"/> and generates C# code with the given options.
    /// </summary>
    private static string Generate(string protoSchema, string? ns = null, GeneratorOptions? opts = null)
    {
        var set = new FileDescriptorSet();
        using (var reader = new System.IO.StringReader(protoSchema))
        {
            set.Add("test.proto", source: reader);
        }
        set.Process();
        var errors = set.GetErrors();
        if (errors.Length > 0)
            throw new InvalidOperationException(string.Join(Environment.NewLine, errors.Select(e => e.ToString())));

        var file = set.Files.First();
        return new LightProtoCSharpGenerator(opts).Generate(file, ns);
    }

    /// <summary>
    /// Formats a C# code string with CSharpier, producing deterministic output.
    /// </summary>
    private static async Task<string> FmtAsync(string code)
    {
        var result = await CSharpFormatter.FormatAsync(code, new CSharpier.Core.CodeFormatterOptions());
        return result.Code ?? code;
    }

    /// <summary>
    /// Asserts that <paramref name="generatedCode"/> and <paramref name="expectedCode"/>,
    /// after being formatted by CSharpier, are identical strings.
    /// </summary>
    private static async Task AssertCodeEqual(string generatedCode, string expectedCode)
    {
        // TrimEnd() normalises trailing-newline differences only (raw string literals in C#
        // don't include a final newline, but CSharpier always appends one to formatted files).
        var fmtGenerated = (await FmtAsync(generatedCode)).TrimEnd();
        var fmtExpected = (await FmtAsync(expectedCode)).TrimEnd();
        await Assert.That(fmtGenerated).IsEqualTo(fmtExpected);
    }

    // -------------------------------------------------------------------------
    // Baseline: attributes and class declaration
    // -------------------------------------------------------------------------

    [Test]
    public async Task GeneratesProtoContractAttribute()
    {
        var code = Generate(
            """
            syntax = "proto3";
            message MyMessage { int32 id = 1; }
            """,
            "TestNs"
        );

        const string expected = """
            // <auto-generated/>
            // This file was generated by lightproto-gen. Do not edit manually.
            #nullable enable

            namespace TestNs
            {
                [global::LightProto.ProtoContract]
                public partial class MyMessage
                {
                    [global::LightProto.ProtoMember(1)]
                    public int? Id { get; set; }
                }
            }
            """;

        await AssertCodeEqual(code, expected);
    }

    [Test]
    public async Task GeneratesProtoMemberTagNumbers()
    {
        var code = Generate(
            """
            syntax = "proto3";
            message Msg { string first = 1; int32 second = 42; }
            """,
            "TestNs"
        );

        const string expected = """
            // <auto-generated/>
            // This file was generated by lightproto-gen. Do not edit manually.
            #nullable enable

            namespace TestNs
            {
                [global::LightProto.ProtoContract]
                public partial class Msg
                {
                    [global::LightProto.ProtoMember(1)]
                    public string? First { get; set; }

                    [global::LightProto.ProtoMember(42)]
                    public int? Second { get; set; }
                }
            }
            """;

        await AssertCodeEqual(code, expected);
    }

