    // -------------------------------------------------------------------------
    // oneof handling
    // -------------------------------------------------------------------------

    [Test]
    public async Task OneofWithAllMessageFieldsGeneratesProtoInclude()
    {
        // UseProtoIncludeForOneof must be explicitly set; default is false.
        var opts = new GeneratorOptions { UseProtoIncludeForOneof = true };
        var code = Generate(
            """
            syntax = "proto3";
            message Dog  { string breed = 1; }
            message Cat  { bool indoor = 1; }
            message Animal {
              oneof kind {
                Dog dog = 1;
                Cat cat = 2;
              }
            }
            """,
            "TestNs",
            opts
        );

        const string expected = """
            // <auto-generated/>
            // This file was generated by lightproto-gen. Do not edit manually.
            #nullable enable

            namespace TestNs
            {
                [global::LightProto.ProtoContract]
                public partial class Dog
                {
                    [global::LightProto.ProtoMember(1)]
                    public string? Breed { get; set; }
                }

                [global::LightProto.ProtoContract]
                public partial class Cat
                {
                    [global::LightProto.ProtoMember(1)]
                    public bool? Indoor { get; set; }
                }

                [global::LightProto.ProtoContract]
                [global::LightProto.ProtoInclude(1, typeof(Dog))]
                [global::LightProto.ProtoInclude(2, typeof(Cat))]
                public partial class Animal
                {
                }
            }
            """;

        await AssertCodeEqual(code, expected);
    }

